#include <Wire.h>
#include "MAX30105.h"
MAX30105 particleSensor;
void setup() {
  Serial.begin(115200);
  if (!particleSensor.begin(Wire, I2C_SPEED_FAST)) {
    Serial.println("MAX30102 not found!");
    while (1);
  }
  particleSensor.setup();
}
void loop() {
  long ir = particleSensor.getIR();
  Serial.println(ir);
  delay(20);
}
